+    // ── Additional FileDescriptor tests ──────────────────────
+
+    #[test]
+    fn file_descriptor_dup_stderr() {
+        let stderr = std::io::stderr();
+        let handle = stderr.lock();
+        let fd = FileDescriptor::dup(&handle).unwrap();
+        assert!(fd.as_raw_file_descriptor() >= 0);
+    }
